#include <vector>
#include <algorithm>
#include <cmath>
#include <iostream>

using namespace std;

typedef long long ll;

// A structure to represent a segment, used for custom sorting
struct Segment {
    ll ones;
    ll zeros;
    // A value used for comparison: the 'value' of the segment if it were placed before another segment
    // This is derived from the concept of comparing two binary strings $A$ and $B$ to see if $AB > BA$.
    // For a segment S = (w1, z1) and T = (w2, z2), we compare $S+T$ vs $T+S$.
    // $S+T$ starts with $w1$ ones, followed by $z1$ zeros, then $w2$ ones, then $z2$ zeros.
    // $T+S$ starts with $w2$ ones, followed by $z2$ zeros, then $w1$ ones, then $z1$ zeros.

    // A simpler, equivalent heuristic for this specific problem:
    // The segment that contributes more "weight" to the most significant bits (MSBs) should come first.
    // The total length is $L = w + z$.
    // The contribution of $w$ ones followed by $z$ zeros is maximized when $w$ is large, especially relative to $z$.

    // The standard comparison for lexicographically largest concatenation:
    // $A$ should come before $B$ if $A+B > B+A$ lexicographically.
};

// Custom comparator function for sorting segments
bool compareSegments(const Segment& a, const Segment& b) {
    // To compare A+B vs B+A lexicographically, we can simulate the comparison.

    // A = (a.ones, a.zeros), B = (b.ones, b.zeros)

    // Check A+B vs B+A.
    // A+B starts with a.ones '1's.
    // B+A starts with b.ones '1's.

    // 1. Compare the initial blocks of '1's.
    if (a.ones != b.ones) {
        return a.ones > b.ones; // More leading ones is better
    }

    // If the number of leading '1's is the same, the tie-breaker depends on the following digits.
    // After a.ones '1's, A has a.zeros '0's. After b.ones '1's, B has b.zeros '0's.

    // If a.ones == b.ones:
    // A+B: 1...1 (a.ones) | 0...0 (a.zeros) | 1...1 (b.ones) | 0...0 (b.zeros)
    // B+A: 1...1 (b.ones) | 0...0 (b.zeros) | 1...1 (a.ones) | 0...0 (a.zeros)

    // Since a.ones == b.ones, the first block is identical.
    // We compare the part starting from the (a.ones + 1)-th bit.

    // If a.zeros != b.zeros:
    // A+B continues with a.zeros zeros.
    // B+A continues with b.zeros zeros.
    // Since '0' < '1', having fewer initial zeros after the '1' block is generally better,
    // or more accurately, we need to see how many more '1's we can get sooner.

    // The critical comparison is between the '0' block of A followed by '1' block of B,
    // vs the '0' block of B followed by '1' block of A.

    // If a.ones == b.ones:
    // We compare (a.zeros zeros + b.ones ones) vs (b.zeros zeros + a.ones ones)
    // Since a.ones == b.ones, the second part is identical.
    // We compare a.zeros zeros vs b.zeros zeros.
    // This means we prefer the one with fewer zeros immediately following the equal number of ones,
    // as this brings the next block (which starts with '1's) sooner.
    return a.zeros < b.zeros;
}

// Re-evaluating the comparison based on standard competitive programming wisdom for this problem type:
// A segment $S_i$ is best placed before $S_j$ if the number represented by $S_i S_j$ is greater than $S_j S_i$.
// Since the segments are structured as $1...10...0$, the comparison $S_i S_j$ vs $S_j S_i$ boils down to comparing the relative "value density".

// Let $A = (w_a, z_a)$ and $B = (w_b, z_b)$.
// We want $A$ before $B$ if $A+B > B+A$.

// $A+B$: $w_a$ ones, $z_a$ zeros, $w_b$ ones, $z_b$ zeros.
// $B+A$: $w_b$ ones, $z_b$ zeros, $w_a$ ones, $z_a$ zeros.

// 1. Compare $w_a$ vs $w_b$. If $w_a > w_b$, $A+B$ starts with more ones, so $A+B > B+A$. $A$ comes first.
// 2. If $w_a < w_b$, $B+A$ starts with more ones, so $B+A > A+B$. $B$ comes first.
// 3. If $w_a = w_b = w$.
//    $A+B$: $w$ ones, $z_a$ zeros, $w$ ones, $z_b$ zeros.
//    $B+A$: $w$ ones, $z_b$ zeros, $w$ ones, $z_a$ zeros.
//    The first $w$ bits are equal. We compare $0^{z_a} 1^w 0^{z_b}$ vs $0^{z_b} 1^w 0^{z_a}$ starting after the initial $1^w$.
//    We compare $0^{z_a}$ vs $0^{z_b}$ followed by the rest. This is complicated.

// Let's use the property that $10...0$ is $2^{w+z} - 2^{z}$.
// A more robust comparison for this specific pattern $1^w 0^z$:
// Compare $w_a / (z_a+1)$ vs $w_b / (z_b+1)$ is often used for variable length items, but here the structure is fixed.

// The simplest working greedy strategy is: prioritize segments that have a higher ratio of '1's to '0's, breaking ties by total length, but the standard lexicographical comparison $A+B > B+A$ must hold.

// Given $w_a=w_b=w$:
// $A+B = 1^w 0^{z_a} 1^w 0^{z_b}$
// $B+A = 1^w 0^{z_b} 1^w 0^{z_a}$
// If $z_a < z_b$, then $A+B$ has fewer zeros immediately after the first $1^w$ block, so $A+B > B+A$. $A$ comes first.

// Conclusion for comparison:
// 1. Sort by $w$ descending.
// 2. If $w$ equal, sort by $z$ ascending.

bool compareSegments_final(const Segment& a, const Segment& b) {
    if (a.ones != b.ones) {
        return a.ones > b.ones; // More ones first
    }
    // If ones are equal, fewer zeros first (to push the next block of ones earlier)
    return a.zeros < b.zeros;
}


class Solution {
private:
    ll power(ll base, ll exp) {
        ll res = 1;
        base %= 1000000007;
        while (exp > 0) {
            if (exp % 2 == 1) res = (res * base) % 1000000007;
            base = (base * base) % 1000000007;
            exp /= 2;
        }
        return res;
    }

public:
    int64 solve(vector<int64> nums1, vector<int64> nums0) {
        const int64 MOD = 1e9 + 7;
        int n = nums1.size();
        vector<Segment> segments(n);

        for (int i = 0; i < n; ++i) {
            segments[i] = {nums1[i], nums0[i]};
        }

        // Sort the segments using the custom comparator
        sort(segments.begin(), segments.end(), compareSegments_final);

        int64 total_value = 0;
        int64 current_power_of_2 = 1; // Represents 2^k, starting from k=0 (rightmost bit)

        // We process the segments in the determined optimal order (MSB first).
        // Since we are building the number from left to right (MSB to LSB),
        // we need to calculate the value contribution of each segment based on its position.

        // Total number of bits = sum(nums1[i] + nums0[i])
        int64 total_length = 0;
        for(int i=0; i<n; ++i) {
            total_length += (nums1[i] + nums0[i]);
        }

        // The leftmost bit is at position total_length - 1.
        // We will iterate through the sorted segments and calculate the value contributed by the '1's in each.

        ll current_bit_position = total_length - 1; // Position of the MSB (0-indexed from right)

        for (int i = 0; i < n; ++i) {
            const auto& seg = segments[i];
            ll ones = seg.ones;
            ll zeros = seg.zeros;

            // Contribution from '1's:
            // The '1's are at positions:
            // [current_bit_position - ones + 1] up to [current_bit_position]

            for (ll j = 0; j < ones; ++j) {
                // The current '1' contributes 2^(current_bit_position - j)
                ll exponent = current_bit_position - j;
                ll contribution = power(2, exponent);
                total_value = (total_value + contribution) % MOD;
            }

            // Update the bit position for the next segment:
            // The next segment starts after these 'ones' and 'zeros' bits.
            current_bit_position -= (ones + zeros);
        }

        return total_value;
    }
};
