#include <cmath>

using namespace std;

// Function to compare two segments based on which one should come first
// Segment A: nums1[a] ones, nums0[a] zeros -> value_a
// Segment B: nums1[b] ones, nums0[b] zeros -> value_b
// We prefer A before B if value_a * 2^len(B) + value_b > value_b * 2^len(A) + value_a
// This is equivalent to comparing:
// value_a / 2^len(A) vs value_b / 2^len(B) if they were normalized, but that's complicated.
// A simpler greedy approach is to compare the value obtained by concatenating A then B
// vs B then A.
// Concatenate A then B: A followed by B.
// Concatenate B then A: B followed by A.
// We want to put A before B if (A || B) > (B || A) lexicographically, 
// which translates to a larger resulting integer.

// Let's use the property derived from similar problems (like largest number from digits):
// A segment (n1_a, n0_a) should come before (n1_b, n0_b) if the string 
// of A followed by B is lexicographically greater than the string of B followed by A.

struct Segment {
    long long n1;
    long long n0;
};

// Custom comparison function for sorting
// Returns true if segment a should come before segment b
bool compareSegments(const Segment& a, const Segment& b) {
    // Compare the string A+B vs B+A lexicographically.
    // A = 1...1 (n1_a times) followed by 0...0 (n0_a times)
    // B = 1...1 (n1_b times) followed by 0...0 (n0_b times)

    // A+B: [1^n1_a][0^n0_a][1^n1_b][0^n0_b]
    // B+A: [1^n1_b][0^n0_b][1^n1_a][0^n0_a]

    // Since we are maximizing the integer value, we prioritize longer prefixes of '1's.
    // The comparison must be based on the resulting binary number.

    // If n1_a > n1_b, A starts with more 1s, which is usually better.
    // If n1_a = n1_b, the next differing character determines the order.

    // Let's compare the conceptual values A+B vs B+A.

    // The most significant bits are determined by the sequence of 1s.

    // Case 1: n1_a > 0 and n1_b > 0
    // Both start with 1s. The longer initial run of 1s is better.
    if (a.n1 > b.n1) return true;
    if (a.n1 < b.n1) return false;

    // If n1_a == n1_b > 0, the next bit after the common '1's is:
    // In A+B: '0' if n0_a > 0, or '1' if n0_a = 0 and n1_b > 0.
    // In B+A: '0' if n0_b > 0, or '1' if n0_b = 0 and n1_a > 0.

    // This string comparison approach is complex because of the structure.
    // Let's use the standard approach: compare (A || B) vs (B || A) lexicographically.

    // String A+B:
    string ab = "";
    ab += string(a.n1, '1');
    ab += string(a.n0, '0');
    ab += string(b.n1, '1');
    ab += string(b.n0, '0');

    // String B+A:
    string ba = "";
    ba += string(b.n1, '1');
    ba += string(b.n0, '0');
    ba += string(a.n1, '1');
    ba += string(a.n0, '0');

    return ab > ba;
}

long long solve(vector<long long> nums1, vector<long long> nums0) {
    int n = nums1.size();
    vector<Segment> segments(n);
    for (int i = 0; i < n; ++i) {
        segments[i] = {nums1[i], nums0[i]};
    }

    // Sort the segments using the custom comparator
    sort(segments.begin(), segments.end(), compareSegments);

    long long MOD = 1e9 + 7;
    long long result = 0;
    long long power_of_2 = 1; // Represents 2^k mod MOD, starting from 2^0

    // The segments are now ordered to maximize the resulting integer.
    // We process them from the *last* segment to the *first* segment
    // because the last segment contributes to the least significant bits (lowest power of 2).

    // Total length of the string is Sum(n1_i + n0_i).
    // The first segment (segments[0]) contributes the most significant bits.

    // We calculate the value iteratively:
    // Result = (Result * 2^len(next_segment) + value(next_segment)) mod MOD
    // where value(next_segment) is the integer represented by that segment.

    // Let's calculate the total length first, or iterate forward and maintain the power of 2 for the current segment's contribution.

    long long current_multiplier = 1; // Represents 2^(total length of segments already processed)

    // Iterate through the segments in the sorted order (most significant first)
    for (int i = 0; i < n; ++i) {
        const auto& seg = segments[i];

        // Segment value contribution:
        // The segment has n1 ones followed by n0 zeros.
        // The value is: (2^n1 - 1) * 2^n0  (if n1>0)
        // Value = sum_{j=n0}^{n0+n1-1} 2^j

        // If n1 = 0, value is 0.
        if (seg.n1 == 0) {
            // Segment is all zeros, value contribution is 0.
            // The length is n0. We just update the multiplier for the next segment.
            long long len = seg.n0;
            for(int k = 0; k < len; ++k) {
                current_multiplier = (current_multiplier * 2) % MOD;
            }
            continue;
        }

        // The value of a segment with n1 ones followed by n0 zeros:
        // Value = (2^n1 - 1) * 2^n0

        // Calculate 2^n1 - 1 mod MOD
        long long val_ones = 0;
        long long pow2_n1 = 1;
        for (long long k = 0; k < seg.n1; ++k) {
            val_ones = (val_ones + pow2_n1) % MOD;
            pow2_n1 = (pow2_n1 * 2) % MOD;
        }
        // val_ones is now 2^n1 - 1 mod MOD

        // Calculate 2^n0 mod MOD
        long long pow2_n0 = 1;
        for (long long k = 0; k < seg.n0; ++k) {
            pow2_n0 = (pow2_n0 * 2) % MOD;
        }

        // Value of the segment: (2^n1 - 1) * 2^n0 mod MOD
        long long seg_value = (val_ones * pow2_n0) % MOD;

        // Contribution to the total result:
        // The segment is placed at a position determined by the sum of lengths of preceding segments.
        // The length of the current segment is L = n1 + n0.
        // The contribution is seg_value * 2^(Total_Length_After_This_Segment)

        // The current_multiplier tracks 2^(Total_Length_Of_Preceding_Segments).
        // We need the multiplier for the current segment's position.

        // Let's redefine current_multiplier: it will track 2^(total length of segments *before* the current one).
        // When processing segment i, its contribution is seg_value * 2^(TotalLength - (Length_i + Sum_of_lengths_after_i)).

        // Simpler approach: build the string conceptually and calculate its value.
        // We are calculating V = sum_i (Value_i * 2^(Sum_of_lengths_after_i)) mod MOD.

        long long segment_length = seg.n1 + seg.n0;

        // The factor by which this segment value is scaled depends on the total length of all segments *after* it.
        // Since we process in order, we don't know the total length easily unless we pre-calculate.

        // Let's calculate total length first.
    }

    // Re-implementation using the standard accumulation method (multiply by 2 and add next value)
    long long total_result = 0;

    for (int i = 0; i < n; ++i) {
        const auto& seg = segments[i];

        // 1. Calculate seg_value (integer value of the segment)
        if (seg.n1 == 0) {
            // Value is 0
            // We still need to shift the accumulated result by seg.n0 bits (multiply by 2^n0)
            long long shift = seg.n0;
            long long pow2_shift = 1;
            for(int k = 0; k < shift; ++k) {
                pow2_shift = (pow2_shift * 2) % MOD;
            }
            total_result = (total_result * pow2_shift) % MOD;
            continue;
        }

        // Value = (2^n1 - 1) * 2^n0 mod MOD
        // 2^n1 - 1
        long long val_ones = (pow(2, seg.n1, MOD) - 1 + MOD) % MOD;

        // 2^n0
        long long pow2_n0 = pow(2, seg.n0, MOD);

        long long seg_value = (val_ones * pow2_n0) % MOD;

        // 2. Shift total_result by segment_length (n1 + n0)
        long long shift = seg.n1 + seg.n0;
        long long pow2_shift = pow(2, shift, MOD);
        total_result = (total_result * pow2_shift) % MOD;

        // 3. Add seg_value
        total_result = (total_result + seg_value) % MOD;
    }

    return total_result;
}

// Helper function for modular exponentiation (a^b % m)
long long pow(long long base, long long exp, long long mod) {
