    ll total_length = 0;
    for (const auto& frag : fragments) {
        total_length += (frag.n1 + frag.n0);
    }

    // 重新计算：我们知道最终的字符串 S。我们只需计算 S 的值 $\pmod{10^9+7}$。
    // 从左到右遍历片段 P_k，每遇到 '1' 就将当前结果左移一位并加 1，每遇到 '0' 就左移一位。

    result = 0;
    for (const auto& frag : fragments) {
        // 1. 加上 n1 个 '1'
        // 对于每个 '1'，result = result * 2 + 1
        for (ll k = 0; k < frag.n1; ++k) {
            result = (result * 2) % MOD;
            result = (result + 1) % MOD;
        }

        // 2. 加上 n0 个 '0'
        // 对于每个 '0'，result = result * 2 + 0 (即 result = result * 2)
        for (ll k = 0; k < frag.n0; ++k) {
            result = (result * 2) % MOD;
        }
    }

    return result;
}
