    string s_i = "";
    for (int k = 0; k < i.n1; ++k) s_i += '1';
    for (int k = 0; k < i.n0; ++k) s_i += '0';

    string s_j = "";
    for (int k = 0; k < j.n1; ++k) s_j += '1';
    for (int k = 0; k < j.n0; ++k) s_j += '0';

