        // 考虑 A 在前 (A+B) 和 B 在前 (B+A)。
        // 它们的前缀都是 1...1
        // 它们的第一个差异点通常出现在第一个 0 之后。

        // 1. 比较 o_a + o_b (总 '1' 数) - 这在长度相同的情况下不决定大小。

        // 2. 比较 A 带来的 "1" 在更高位上的贡献。
        // A 的第一个 '1' 贡献是 2^(L-1)。

        // 简化模型：我们看 A 放在 B 前面是否能带来更大的值。
        // 设 A 的“价值因子”为 V_A，B 的“价值因子”为 V_B。
        // V_A 应该与 (o_a, z_a) 的组合相关。

        // 实际上，这个排序问题等价于：
        // 如果 (1^o_a 0^z_a) + (1^o_b 0^z_b) 的数值大于 (1^o_b 0^z_b) + (1^o_a 0^z_a) 的数值，则 A 优于 B。

        // 比较 A+B vs B+A
        // A+B: (o_a ones) followed by (z_a + o_b) ones/zeros, then (z_b zeros)
        // B+A: (o_b ones) followed by (z_b + o_a) ones/zeros, then (z_a zeros)

        // 我们可以通过构建虚拟字符串并比较，因为 N 是有限的 (总长度 <= 2*10^5)。
        // 但为了效率，我们尝试基于 (o, z) 的数学比较。

        // 构造比较函数（C++ std::sort 的 compare function 必须返回 true 如果 *this < other，即 *this 应该排在 other 的前面）
        // 我们需要一个自定义的排序，使得排序后的序列 S 满足 S[i] 优于 S[j] 当 i < j。
        // 所以，如果 A 优于 B (A 应该排在 B 前面)，则返回 A < B 为 true。

        // A 优于 B <=> (A+B) > (B+A)
        // A < B (在排序中) <=> A 应该排在 B 前面 <=> (A+B) > (B+A)

        // 我们可以利用一个技巧：
        // 设 P_A = 2^(o_a + z_a) (A的长度)
        // 设 P_B = 2^(o_b + z_b) (B的长度)

        // A+B 的值 = Value(A) * 2^(o_b + z_b) + Value(B)
        // B+A 的值 = Value(B) * 2^(o_a + z_a) + Value(A)

        // 因为我们只需要比较 A+B vs B+A，我们可以直接构造字符串比较。
        // 考虑到总长度 <= 2*10^5，字符串操作是可接受的，但我们避免它。

        // 终极贪心：如果两个片段 A 和 B，我们总是把那个“看起来更像 1 开头且持续时间更长”的排在前面。

        // 如果 o_a > o_b, A 更有潜力在前面贡献更多高的位 1，倾向于 A > B
        if (ones != other.ones) {
            return ones > other.ones; // 更多 1 的优先
        }
        // 如果 ones 相同，看 zeros。较少的 0 意味着更长的 1 序列或更早地过渡到 0。
        return zeros < other.zeros; // 较少 0 的优先 (更长的 1 块或更短的 0 块)
    }
};


long long power(long long base, long long exp) {
    long long res = 1;
    base %= 1000000007;
    while (exp > 0) {
        if (exp % 2 == 1) res = (res * base) % 1000000007;
        base = (base * base) % 1000000007;
        exp /= 2;
    }
    return res;
}

long long solve(vector<long long> nums1, vector<long long> nums0) {
    long long MOD = 1000000007;
    int n = nums1.size();
    vector<Segment> segments;

    for (int i = 0; i < n; ++i) {
        segments.push_back({nums1[i], nums0[i]});
    }

    // 使用自定义的排序规则：A 优于 B <=> (A+B) > (B+A)
    // 为了实现这个复杂的比较，我们必须使用一个稳定的比较器，它模拟字符串拼接比较。

    auto compare_segments = [&](const Segment& a, const Segment& b) -> bool {
        // Returns true if 'a' should come before 'b' (i.e., a is "greater" in the sense of lexicographical value)

        // Compare A+B vs B+A. We want A+B > B+A.

        // A+B: 1^a.ones 0^a.zeros 1^b.ones 0^b.zeros
        // B+A: 1^b.ones 0^b.zeros 1^a.ones 0^a.zeros

        // Since the total length is fixed (L = a.ones + a.zeros + b.ones + b.zeros), 
        // lexicographical comparison is equivalent to numerical comparison.

        // Constructing the comparison string virtually is the safest approach here, 
        // given the constraints and the difficulty of deriving a purely algebraic comparison 
        // that handles the transition points correctly for all cases.

        // String comparison simulation:

        // 1. Check the first differing character

        // Start comparing A+B vs B+A character by character until the end.
        // A+B sequence: 1...1 (o_a), 0...0 (z_a), 1...1 (o_b), 0...0 (z_b)
        // B+A sequence: 1...1 (o_b), 0...0 (z_b), 1...1 (o_a), 0...0 (z_a)

        long long current_a_ones = a.ones;
        long long current_a_zeros = a.zeros;
        long long current_b_ones = b.ones;
        long long current_b_zeros = b.zeros;

        // Pointers/counts for A+B (Left to Right) and B+A (Left to Right)
        long long pa_ones = a.ones, pa_zeros = a.zeros;
        long long pb_ones = b.ones, pb_zeros = b.zeros;

        // Simulate A+B
        vector<char> ab_str;
        for (int i = 0; i < pa_ones; ++i) ab_str.push_back('1');
        for (int i = 0; i < pa_zeros; ++i) ab_str.push_back('0');
        for (int i = 0; i < pb_ones; ++i) ab_str.push_back('1');
        for (int i = 0; i < pb_zeros; ++i) ab_str.push_back('0');

        // Simulate B+A
        vector<char> ba_str;
        for (int i = 0; i < pb_ones; ++i) ba_str.push_back('1');
        for (int i = 0; i < pb_zeros; ++i) ba_str.push_back('0');
        for (int i = 0; i < pa_ones; ++i) ba_str.push_back('1');
        for (int i = 0; i < pa_zeros; ++i) ba_str.push_back('0');

        // Since total length is small enough (<= 2*10^5), string comparison is safe.
        // We return true if a should come before b, which means A+B > B+A
        return ab_str > ba_str;
    };

    sort(segments.begin(), segments.end(), compare_segments);

    // Calculate the final result modulo 10^9 + 7
    long long total_value = 0;
    long long current_power_of_2 = 1; // Represents 2^0

    // The segments are now ordered optimally: S_0, S_1, ..., S_{n-1}
    // The string is S_0 S_1 ... S_{n-1}

    for (int i = n - 1; i >= 0; --i) {
        const auto& seg = segments[i];

        // Segment S_i has length L_i = seg.ones + seg.zeros.
        // When calculating the value of S_i, it contributes to bits starting at position 
        // (sum of lengths of S_{i+1} to S_{n-1}) relative to the end.

        // We calculate the value contribution of S_i.
        // S_i = 1...1 (o_i) 0...0 (z_i)

        // Contribution of 1s:
        // Each '1' at position j (from the right, 0-indexed) contributes 2^j.
        // The '1's are the first o_i bits of S_i.
        // The position of the last bit of S_i (rightmost '0' or last '1') is 
        // determined by the total length of subsequent segments.

        // Let L_suffix = sum_{j=i+1}^{n-1} (o_j + z_j). This is the number of bits to the right of S_i.
        // The rightmost bit of S_i is at position L_suffix.

        // The first '1' of S_i is at position L_suffix + seg.zeros.
        // The last '1' of S_i is at position L_suffix + seg.zeros + seg.ones - 1.

        // Let's use the current_power_of_2 trick, iterating backwards from the end of the full string.
        // current_power_of_2 must track 2^(total_length_of_remaining_segments).
    }

    // Reset and use a simpler accumulation method based on position.
    long long result = 0;
    long long total_length = 0;
    for(const auto& seg : segments) {
        total_length += seg.ones + seg.zeros;
    }

    for (int i = 0; i < n; ++i) {
        const auto& seg = segments[i];
        long long L_suffix = 0;
        for(int j = i + 1; j < n; ++j) {
            L_suffix += segments[j].ones + segments[j].zeros;
        }

        // S_i = 1^o_i 0^z_i

        // Contribution of 0s: They contribute 0 to the sum, so we only care about the length shift.
        // The o_i ones start at position L_suffix + z_i (0-indexed from the right).

        // The first '1' is at bit position P_start = L_suffix + seg.zeros.
        // The last '1' is at bit position P_end = L_suffix + seg.zeros + seg.ones - 1.

        // Sum of 2^j for j from P_start to P_end:
        // Sum = 2^P_start + 2^(P_start+1) + ... + 2^(P_end)
        // Sum = 2^P_start * (2^(seg.ones) - 1)

        long long P_start = L_suffix + seg.zeros;

        // Term 1: 2^seg.ones - 1 (mod MOD)
        long long term1 = (power(2, seg.ones) - 1 + MOD) % MOD;

        // Term 2: 2^P_start (mod MOD)
        long long term2 = power(2, P_start);

        // Contribution = Term1 * Term2 (mod MOD)
        long long contribution = (term1 * term2) % MOD;

        result = (result + contribution) % MOD;
    }

    return result;
}
